/**
 * vendor/psl.min.js
 * Public Suffix List shim for HPP Chrome Extension.
 *
 * This is a functional stub that handles the most common TLDs correctly.
 * For production deployment, replace this file with the real psl library:
 *   https://github.com/lupomontero/psl  (npm install psl)
 *   Run: node -e "require('fs').writeFileSync('vendor/psl.min.js', require('fs').readFileSync('node_modules/psl/dist/psl.min.js'))"
 *
 * The hpp-crypto.js computeRpId() function will prefer this if typeof psl !== 'undefined'.
 *
 * Spec reference: Section 4.2 — WebAuthn rp.id must use eTLD+1 (PSL-aware).
 */

/* global psl */
var psl = (function() {
  'use strict';

  // Abbreviated multi-part TLD list for common cases
  // Full PSL has ~9000 entries; this covers the major ones
  var MULTI_PART = {
    'co.uk':1,'co.jp':1,'co.nz':1,'co.za':1,'co.in':1,'co.kr':1,
    'com.au':1,'com.br':1,'com.mx':1,'com.ar':1,'com.cn':1,'com.hk':1,
    'com.sg':1,'com.tw':1,'com.vn':1,'com.tr':1,
    'org.uk':1,'net.uk':1,'gov.uk':1,'ac.uk':1,'me.uk':1,'ltd.uk':1,
    'gov.au':1,'edu.au':1,'id.au':1,'net.au':1,'org.au':1,
    'ne.jp':1,'or.jp':1,'ac.jp':1,'go.jp':1,'ed.jp':1,
    'gov.br':1,'edu.br':1,'org.br':1,'net.br':1,
    'gob.mx':1,'edu.mx':1,
  };

  /**
   * Returns the registrable domain (eTLD+1) for a given hostname.
   * e.g. 'login.example.co.uk' → 'example.co.uk'
   *      'foo.bar.example.com' → 'example.com'
   */
  function get(hostname) {
    if (!hostname) return null;
    hostname = hostname.toLowerCase().replace(/\.$/, '');

    var parts = hostname.split('.');
    if (parts.length < 2) return hostname;

    // Check for 2-part TLD (e.g. co.uk)
    if (parts.length >= 3) {
      var tld2 = parts.slice(-2).join('.');
      if (MULTI_PART[tld2]) {
        // eTLD+1 is 3 labels: e.g. example.co.uk
        return parts.slice(-3).join('.');
      }
    }

    // Default: eTLD+1 is last 2 labels
    return parts.slice(-2).join('.');
  }

  /**
   * Returns true if the hostname is a valid registrable domain
   * (not a TLD itself, not a bare hostname).
   */
  function isValid(hostname) {
    var parsed = get(hostname);
    return !!parsed && parsed.indexOf('.') !== -1;
  }

  return { get: get, isValid: isValid };
})();
